mapper.select:
SELECT v.id as vehicle_id, v.vehicle_name, v.infotainment_software_version, ts.score,ts.video_name as state_video_name FROM test_case tc left join test_state ts on tc.id = ts.testcase_id left join test_record tr on tr.id = ts.record_id left join vehicle v on tr.vehicle_id = v.id where ts.test_status = 1 and ts.testcase_id = #{testCaseId}
and v.id IN
#{id}

SELECT VAR_POP(ts.score) as variance_value
FROM test_case tc
         left join test_state ts on tc.id = ts.testcase_id
         left join test_record tr on tr.id = ts.record_id
         left join vehicle v on tr.vehicle_id = v.id
where ts.test_status = 1
  and tc.id = #{testCaseId}

    and v.id IN

        #{id}


GROUP BY tc.id;

select DISTINCT tc.task_detail,ts.function_evaluate,ts.data_state
from test_case tc
left join function_tree_state ts
    on tc.task_detail = ts.task_detail
    and ts.record_id=#{testRecordId}
    and ts.deleted = 0
where tc.scenario_id = #{scenarioId}

    and tc.task_detail LIKE CONCAT(#{type}, "%")


    AND tc.function_id = #{functionId}


    and (ts.function_evaluate = #{functionEvaluate} or ts.function_evaluate IS NULL)


    and ts.function_evaluate = #{functionEvaluate}


    and (ts.data_state = #{dataState} or ts.data_state IS NULL )


    and ts.data_state = #{dataState}


    and tc.id = #{testCaseId}

select tc.*,ts.material_state,ts.test_case_rate
from test_case tc
left join test_state ts on ts.testcase_id = tc.id and ts.record_id=#{testRecordId}
where tc.scenario_id = #{scenarioId}
and tc.task_detail = #{taskDetail}

    and tc.function_id = #{functionId}


    and tc.scenario_task = #{scenarioTask}

select DISTINCT tc.task_detail
from test_case tc
where tc.scenario_id = #{scenarioId}

SELECT id,testcase_content,task_detail
FROM `test_case` where scenario_id = 6
AND task_detail = #{functionId}
